css:
:root{--bg:#050509;--s1:#0c0c15;--s2:#131320;--brd:#222240;--brd2:#333358;--tx:#d0d0e6;--tx2:#8888aa;--tx3:#5e5e80;--w:#f2f2ff;--green:#34d399;--red:#f87171;--yellow:#fbbf24;--purple:#a78bfa;--blue:#60a5fa;--pink:#f472b6;--code-bg:#08080f;--r:10px}
*{margin:0;padding:0;box-sizing:border-box}html{scroll-behavior:smooth}
body{font-family:'Manrope',sans-serif;background:var(--bg);color:var(--tx);line-height:1.7;font-size:14.5px;-webkit-font-smoothing:antialiased}
::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:var(--bg)}::-webkit-scrollbar-thumb{background:var(--purple);border-radius:9px}
.hero{padding:2.5rem 1.5rem 1rem;text-align:center;position:relative;overflow:hidden}
.hero::before{content:'';position:absolute;inset:0;background:radial-gradient(ellipse 80% 60% at 50% -10%,rgba(167,139,250,.1),transparent 60%);pointer-events:none}
.hero h1{font-family:'Literata',serif;font-size:clamp(1.8rem,5vw,3rem);font-weight:900;color:var(--w);letter-spacing:-.03em;line-height:1.15;position:relative}
.hero .sub{color:var(--tx2);margin-top:.4rem;font-size:.83rem}
.tabs{display:flex;justify-content:center;gap:.4rem;padding:.55rem .8rem;flex-wrap:wrap;border-bottom:1px solid var(--brd);position:sticky;top:0;z-index:1000;background:rgba(5,5,9,.92);backdrop-filter:blur(20px)}
.tab{font-family:'Manrope',sans-serif;font-size:.76rem;font-weight:700;padding:.45rem 1rem;border-radius:8px;border:1px solid var(--brd);background:var(--s1);color:var(--tx2);cursor:pointer;transition:.2s}
.tab:hover{border-color:var(--tx3);color:var(--tx)}.tab.active{color:var(--w);border-color:var(--purple);background:rgba(167,139,250,.1)}
.sub-nav{overflow-x:auto;white-space:nowrap;padding:.35rem .8rem;border-bottom:1px solid var(--brd);position:sticky;top:44px;z-index:999;background:rgba(5,5,9,.88);backdrop-filter:blur(16px)}
.sub-nav::-webkit-scrollbar{height:0}
.sni{display:flex;gap:0;max-width:1300px;margin:0 auto}
.sn{background:0;border:0;color:var(--tx3);font-family:'Manrope',sans-serif;font-size:.7rem;font-weight:500;padding:.55rem .75rem;cursor:pointer;border-bottom:2px solid transparent;transition:.2s;white-space:nowrap}
.sn:hover{color:var(--tx)}.sn.active{color:var(--purple);border-bottom-color:var(--purple)}
.mn{max-width:880px;margin:0 auto;padding:1.5rem 1.25rem 5rem}
.ts{display:none}.ts.active{display:block}
.sc{display:none;animation:fu .3s ease}.sc.active{display:block}
@keyframes fu{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}
.si{font-size:.88rem;color:var(--tx2);margin-bottom:1.2rem;padding-bottom:.9rem;border-bottom:1px solid var(--brd)}
.cd{background:var(--s1);border:1px solid var(--brd);border-radius:var(--r);padding:1.4rem;margin-bottom:.9rem;transition:border-color .3s}
.cd:hover{border-color:var(--brd2)}
.cd h2{font-family:'Literata',serif;font-size:1.2rem;font-weight:700;color:var(--w);margin-bottom:.5rem}
.cd h3{font-size:.9rem;font-weight:700;color:var(--green);margin:1rem 0 .4rem}
.cd h4{font-size:.82rem;font-weight:600;color:var(--purple);margin:.8rem 0 .3rem}
pre{background:var(--code-bg);border:1px solid var(--brd);border-radius:8px;padding:.85rem;overflow-x:auto;margin:.4rem 0;font-size:.72rem;line-height:1.55;tab-size:2}
code{font-family:'JetBrains Mono',monospace;font-size:.72rem}
p code,li code{background:var(--s2);padding:.08em .3em;border-radius:4px;color:var(--pink);font-size:.72em}
.k{color:#c792ea}.s{color:#c3e88d}.c{color:#546e7a}.f{color:#82aaff}.d{color:#ffcb6b}.n{color:#f78c6c}
.qa{background:var(--s1);border:1px solid var(--brd);border-radius:var(--r);margin-bottom:.4rem;overflow:hidden}
.qh{padding:.7rem .9rem;cursor:pointer;display:flex;align-items:flex-start;gap:.55rem;user-select:none;transition:background .2s}
.qh:hover{background:var(--s2)}
.lv{font-family:'JetBrains Mono',monospace;font-size:.5rem;font-weight:600;padding:.1rem .4rem;border-radius:20px;text-transform:uppercase;letter-spacing:.04em;flex-shrink:0;margin-top:.15rem}
.lv.b{background:rgba(52,211,153,.1);color:var(--green)}.lv.i{background:rgba(251,191,36,.1);color:var(--yellow)}.lv.a{background:rgba(248,113,113,.1);color:var(--red)}
.qt{font-weight:600;font-size:.8rem;color:var(--w);flex:1}
.tg{color:var(--tx3);font-size:.95rem;flex-shrink:0;transition:transform .3s}
.qa.open .tg{transform:rotate(45deg)}
.qb{max-height:0;overflow:hidden;transition:max-height .5s ease}
.qa.open .qb{max-height:15000px}
.qi{padding:0 .9rem .9rem}.qi p{margin-bottom:.3rem}
.fb{display:flex;gap:.3rem;margin-bottom:.6rem;flex-wrap:wrap}
.ft{background:var(--s1);border:1px solid var(--brd);color:var(--tx3);font-family:'Manrope',sans-serif;font-size:.68rem;font-weight:500;padding:.3rem .65rem;border-radius:20px;cursor:pointer;transition:.2s}
.ft:hover{border-color:var(--tx3)}.ft.active{background:var(--purple);border-color:var(--purple);color:#fff}
.ct{font-size:.72rem;color:var(--tx3);margin-bottom:.5rem}.ct b{color:var(--purple)}
.an{background:rgba(167,139,250,.06);border-left:3px solid var(--purple);border-radius:0 8px 8px 0;padding:.7rem .85rem;margin:.4rem 0;font-size:.78rem}
.an::before{content:'💡 Think of it this way';display:block;font-weight:700;font-size:.6rem;color:var(--purple);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.2rem}
.tp{background:rgba(52,211,153,.06);border-left:3px solid var(--green);border-radius:0 8px 8px 0;padding:.7rem .85rem;margin:.4rem 0;font-size:.78rem}
.tp::before{content:'🔥 Pro Tip';display:block;font-weight:700;font-size:.6rem;color:var(--green);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.2rem}
.wr{background:rgba(251,191,36,.06);border-left:3px solid var(--yellow);border-radius:0 8px 8px 0;padding:.7rem .85rem;margin:.4rem 0;font-size:.78rem}
.wr::before{content:'⚠️ Common Mistake';display:block;font-weight:700;font-size:.6rem;color:var(--yellow);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.2rem}
.dp{background:rgba(96,165,250,.06);border-left:3px solid var(--blue);border-radius:0 8px 8px 0;padding:.7rem .85rem;margin:.4rem 0;font-size:.78rem}
.dp::before{content:'🔬 Under the Hood';display:block;font-weight:700;font-size:.6rem;color:var(--blue);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.2rem}
ul,ol{padding-left:1.2rem;margin:.3rem 0}li{margin-bottom:.2rem}p{margin-bottom:.35rem}strong{color:var(--w)}
@media(max-width:640px){.cd{padding:1rem}pre{padding:.7rem;font-size:.66rem}.qh{padding:.6rem .75rem}.tab{padding:.35rem .7rem;font-size:.7rem}}

scripts:
document.querySelectorAll('.tab').forEach(tab=>{
  tab.addEventListener('click',()=>{
    document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));
    document.querySelectorAll('.ts').forEach(s=>s.classList.remove('active'));
    tab.classList.add('active');
    const ts=document.getElementById(tab.dataset.t);
    if(ts){
      ts.classList.add('active');
      ts.querySelectorAll('.sn').forEach(s=>s.classList.remove('active'));
      ts.querySelectorAll('.sc').forEach(s=>s.classList.remove('active'));
      const f=ts.querySelector('.sn');if(f)f.classList.add('active');
      const g=ts.querySelector('.sc');if(g)g.classList.add('active');
    }
    window.scrollTo({top:0,behavior:'smooth'});
  });
});
document.querySelectorAll('.sn').forEach(btn=>{
  btn.addEventListener('click',()=>{
    const p=btn.closest('.ts');
    p.querySelectorAll('.sn').forEach(b=>b.classList.remove('active'));
    p.querySelectorAll('.sc').forEach(s=>s.classList.remove('active'));
    btn.classList.add('active');
    const t=p.querySelector('#'+btn.dataset.s);
    if(t)t.classList.add('active');
  });
});
document.querySelectorAll('.qh').forEach(h=>{
  h.addEventListener('click',()=>h.parentElement.classList.toggle('open'));
});
document.querySelectorAll('.ft').forEach(btn=>{
  btn.addEventListener('click',()=>{
    const sec=btn.closest('.sc');if(!sec)return;
    sec.querySelectorAll('.ft').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    const f=btn.dataset.f;
    sec.querySelectorAll('.qa').forEach(qa=>{
      qa.style.display=(f==='all'||qa.dataset.l===f)?'':'none';
    });
    const v=sec.querySelectorAll('.qa:not([style*="display: none"])').length;
    sec.querySelectorAll('.ct b').forEach(c=>c.textContent=v);
  });
});
